  dateNumber={formatDate(item.date)}
  statusTitle="Status do pedido"
  status={item.status}
  ghostButtonText="Exibir detalhes"
  onGhostButtonPress={() => handleDetailsOrders(...)}
  type="extended"
  typeTag={STATUS_COLORS[item.status] ?? 'alert'}
  version="2.0"
/>
```

---

### 2. Image Component

**Location**: `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/node_modules/@semparar/design-system-app/src/atomic/atoms/Image/index.tsx`

**Implementation**: Styled-components wrapper around React Native's `Image`

**Props Interface** (`PropsImage`):
```typescript
{
  width?: string | number;
  height?: string | number;
  maxWidth?: string | number;
  minWidth?: string | number;
  minHeight?: string | number;
  maxHeight?: string | number;
  mr/ml/mt/mb?: spacing tokens;
  resizeMode?: 'cover' | 'contain' | 'stretch' | 'repeat' | 'center';
  borderRadiusTopLeft/TopRight/BottomLeft/BottomRight?: radius tokens;
  bgColor?: PropsTokenColorsCore;
  position?: 'relative' | 'absolute';
  index?: number;
}
```

**How MyOrdersRewardProgram uses it**:
```typescript
<Image
  resizeMode="contain"
  source={{ uri: emptyImage }}  // Note: source not in types but works at runtime
  width={80}
  height={80}
/>
```

**Note**: The code includes a `@ts-ignore` comment because `source` prop is not in the TypeScript definition, but works at runtime.

---

### 3. Skeleton Component

**Location**: `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/node_modules/@semparar/design-system-app/src/atomic/atoms/Skeleton/view.tsx`

**Implementation**: Wrapper around `react-native-skeleton-placeholder` with design system tokens

**Props Interface** (`PropsSkeleton`):
```typescript
{
  width: number;  // required
  height: number;  // required
  type?: 'light' | 'dark';  // default: 'light'
  borderRadiusTopLeft?: PropsTokensRadiusCore;
  borderRadiusTopRight?: PropsTokensRadiusCore;
  borderRadiusBottomLeft?: PropsTokensRadiusCore;
  borderRadiusBottomRight?: PropsTokensRadiusCore;
  mt/mb/ml/mr?: spacing tokens;
  testID?: string;
}
```

**Colors**:
- Light type: background `INTENSE_COLOR_02A6`, highlight `BRAND_COMPLEMENT_02A6`
- Dark type: background `INTENSE_COLOR_03A6`, highlight `INTENSE_COLOR_05A6`

**How MyOrdersRewardProgram uses it**:
```typescript
<Skeleton
  testID="loading-orders-cashback"
  width={screenWidth - 64}
  height={150}
  type="light"
  mt="nano"
  mb="nano"
  mr="medium"
  ml="medium"
  borderRadiusTopLeft="half"
/>
```

---

### 4. Store Slice: Extract/Orders Data

**Location**: `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/store/extract.store.ts`

**Slice Name**: `PointsExtractSlice` (exported as part of `RewardsProgramRootStore`)

**State Structure**:
```typescript
{
  pointsExtract: {
    extractData?: {
      transactions: PointsTransaction[];
      pagination: PaginationDto;
    };
    processedExtractData?: ProcessedExtractData;
    status: 'idle' | 'loading' | 'success' | 'error';
    isLoadingMore: boolean;
    error?: string;
  };
  pointsBalance: {
    points?: number;
    status: 'idle' | 'loading' | 'success' | 'error';
    error?: string;
  };
  pointsExtractFilters: {
    appliedTransactionsFilters?: {
      period?: number;
      types?: string[];
      order?: 'ASC' | 'DESC';
    };
    appliedExpiringFilters?: {
      period?: number;
    };
  };
}
```

**Actions** (via `pointsExtractActions`):
- `setExtractStatus(status)`
- `setExtractData(extractData, processedExtractData)`
- `appendExtractData(extractData, processedExtractData)` - for pagination
- `setLoadingMore(isLoading)`
- `setBalanceStatus(status)`
- `setBalance(points)`
- `setTransactionsFilters(filters)` - used by MyOrdersRewardProgram
- `clearTransactionsFilters()` - called on mount/unmount
- `setExpiringFilters(filters)`
- `clearExpiringFilters()`
- `reset()` - clears all state
- `clearBalance()`

**PointsTransaction Interface**:
```typescript
{
  id: string;
  date: string;  // ISO format
  description: string;
  type: 'CREDIT' | 'RESCUE' | 'EXPIRED' | 'REFUNDED';
  amount: number;  // negative for rescue/redemptions
  currencyValue: number;
  icon: string;
  details: {
    provider: string;
    extraInfo: string;
    fields: Array<{ label: string; value: string; }>;
  };
  status: string;  // e.g., 'Pendente', 'Finalizado', 'Estornado', 'Cancelado'
  marketplace?: Marketplace;
  origination?: string;
}
```

**How MyOrdersRewardProgram uses the store**:
```typescript
const { pointsExtract, pointsExtractFilters, pointsExtractActions } = useRootStore(
  useShallow(state => ({
    pointsExtract: state.pointsExtract,
    pointsExtractFilters: state.pointsExtractFilters,
    pointsExtractActions: state.pointsExtractActions,
  })),
);

// Filters transactions by type='Resgate' (rescue/redemption)
getPointsExtract({ type: 'Resgate' });

// Derived data
const myOrders = getFilteredTransactions(
  pointsExtract.extractData?.transactions || [],
  pointsExtractFilters.appliedTransactionsFilters
);
```

---

### 5. STATUS_COLORS Mapping

**Location**: `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/screens/MyOrdersRewardProgram/models/index.ts`

```typescript
export const STATUS_COLORS: Record<string, TypesTagLabel> = {
  Pendente: 'highlight',    // yellow/orange
  Confirmado: 'highlight',  // yellow/orange
  Enviado: 'success',       // green
  Finalizado: 'success',    // green
  Estornado: 'error',       // red
  Cancelado: 'alert',       // gray/muted
};
```

---

### 6. Data Service

**Service**: `getPointsExtract()` from `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/services/extract.service.ts`

**Key Points**:
- Fetches from API via `getPointsExtractApi()`
- Transforms response via `getPointsExtractFromResponse()`
- Processes data via `processPointsExtractData()` for UI consumption
- Supports pagination (page, pageSize parameters)
- Filters by transaction type: `{ type: 'Resgate' }` for orders/redemptions
- Updates Zustand store automatically on success/error
- Includes analytics tracking via `eventServerResponse()`

---

### 7. Store Registration

**File**: `/Users/anotonio.silva/dev/rnm-app-fintech-rewardprogram/src/services/store/slices.ts`

The `PointsExtractSlice` is combined with other slices:
- `ParameterPointsProgramSlice`
- `PermissionSlice`
- `AirlineMilesSlice`
- `PointsProductsSlice`
- `RescueSlice`
- `MarketplaceSlice`
- `OrderDetailSlice`

All exported as `RewardsProgramRootStore` via `setRewardsProgramSlices()` function.

---

### Summary

**MyOrdersRewardProgram** is a filtered view of the extract/transactions data showing only redemptions (`type: 'Resgate'`). It uses:

1. **CardVehicleTags V2** in extended mode to display order cards with status tags
2. **Skeleton** components for loading states (3 skeletons at 150px height)
3. **Image** for empty state illustration
4. **pointsExtract** store slice for data and loading states
5. **Client-side filtering** via `getFilteredTransactions()` util function
6. **Period and order filters** (7/15/30/60/90 days, ASC/DESC)

The data flow is: **API → Service → Repository → Store → Screen**.

