import {
  NavigationProp,
  useFocusEffect,
  useNavigation,
} from '@react-navigation/native';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { format, parseISO } from 'date-fns';
import React, { useCallback, useMemo, useRef, useState } from 'react';
import { Dimensions } from 'react-native';
import { PropsRootStack } from 'src/routes/Models';
import { useShallow } from 'zustand/react/shallow';
import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
import { useRootStore } from '~/store';
import { PERIOD_DAYS_MAP, PointsExtractStatus } from '../../services/models';
import { getPointsExtract } from '../../services/services';
import { FilterGroup } from '../ExtractRewardProgram/Models';
import { getFilteredTransactions } from '../ExtractRewardProgram/utils';
import MyOrdersRewardProgramView from './view';

const PERIOD_FILTERS = [
  {
    label: '7 dias',
    value: 0,
  },
  {
    label: '15 dias',
    value: 1,
  },
  {
    label: '30 dias',
    value: 2,
  },
  {
    label: '60 dias',
    value: 3,
  },
  {
    label: '90 dias',
    value: 4,
  },
];

const TYPE_FILTERS = [
  {
    label: 'Mais recentes',
    value: 'ASC',
  },
  {
    label: 'Mais antigas',
    value: 'DESC',
  },
];

const MyOrdersRewardProgram = () => {
  const [isRefreshing, setIsRefreshing] = useState(false);

  const modalizeRefFilters = useRef<PropsModalizeRef>(null);
  const emptyImage =
    'https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png';

  const SKELETON_COUNT = 3;
  const { width } = Dimensions.get('window');

  const { pointsExtract, pointsExtractFilters, pointsExtractActions } =
    useRootStore(
      useShallow(state => ({
        pointsExtract: state.pointsExtract,
        pointsExtractFilters: state.pointsExtractFilters,
        pointsExtractActions: state.pointsExtractActions,
      })),
    );

  const appliedTransactionsFilters =
    pointsExtractFilters.appliedTransactionsFilters;

  const getFormatDate = (iso?: string) => {
    if (!iso) return '';
    const date = parseISO(iso);
    return format(date, 'dd/MM/yyyy');
  };

  const getFilterGroups: FilterGroup[] = useMemo(() => {
    return [
      {
        label: 'Períodos',
        options: PERIOD_FILTERS,
      },
      {
        label: 'Relevância',
        options: TYPE_FILTERS,
      },
    ];
  }, []);

  const handleApplyFilters = useCallback(
    (filters: Record<number, unknown>) => {
      const period = filters[0] as number | undefined;
      const order = filters[1] as string | undefined;

      const hasPeriod = period !== undefined && period !== null;
      const hasOrdering = order !== undefined && order !== null;

      const parts: string[] = ['filtrar'];

      if (hasPeriod) {
        const periodDay = PERIOD_FILTERS[period].label.split(' ')[0];
        parts.push(`${periodDay}_dias`);
      }

      if (hasOrdering) {
        const label = TYPE_FILTERS.find(item => item.value === order)?.label;
        if (label) {
          parts.push(label === 'Mais recentes' ? 'recentes' : 'antigas');
        }
      }

      eventSelectContent({
        content_type: 'cta',
        content_id: parts.join('_'),
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'meus_pedidos',
      });

      pointsExtractActions.setTransactionsFilters({
        period: hasPeriod
          ? PERIOD_DAYS_MAP[period as keyof typeof PERIOD_DAYS_MAP]
          : undefined,
        order: hasOrdering ? (order as 'ASC' | 'DESC') : undefined,
      });
    },
    [pointsExtractActions],
  );

  const getActiveFiltersCount = useCallback(() => {
    let count = 0;
    if (appliedTransactionsFilters?.period) count++;
    if (appliedTransactionsFilters?.order) count++;
    return count;
  }, [appliedTransactionsFilters]);

  const getInitialFilters = useMemo(() => {
    const initial: Record<number, unknown> = {};

    if (appliedTransactionsFilters?.period) {
      const periodIndex = Object.entries(PERIOD_DAYS_MAP).find(
        ([, days]) => days === appliedTransactionsFilters.period,
      )?.[0];
      if (periodIndex !== undefined) {
        initial[0] = Number(periodIndex);
      }
    }

    if (appliedTransactionsFilters?.order) {
      initial[1] = appliedTransactionsFilters.order;
    }

    return initial;
  }, [appliedTransactionsFilters]);

  const handleOpenFilters = () => {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'filtro_pedidos',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'meus_pedidos',
    });

    modalizeRefFilters.current?.open?.();
  };

  const navigation = useNavigation<NavigationProp<PropsRootStack>>();

  const handleDetailsOrders = (
    transactionId: string,
    type?: string,
    icon?: string,
    status?: string,
    origination?: string
  )=> {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'detalhe_pedido',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'meus_pedidos',
    });

    navigation.navigate('MyOrdersDetails', {
      transactionId,
      type,
      icon,
      status,
      origination,
      analytics: {
        screen_name: 'detalhe_pedido',
        screen_class: 'hub_recompensas_spmais',
        screen_bussines: 'monetizacao',
        screen_info: {
          location_1: 'monetizacao',
          location_2: 'hub_recompensas_spmais',
          location_3: 'detalhe_pedido',
        },
      },
    });
  };

  const myOrders = useMemo(() => {
    const allOrders = pointsExtract?.extractData?.transactions || [];
    return getFilteredTransactions(allOrders, appliedTransactionsFilters);
  }, [
    pointsExtract?.extractData?.transactions,
    appliedTransactionsFilters,
  ]);

  const isLoading = pointsExtract.status === PointsExtractStatus.LOADING;
  const isError = pointsExtract.status === PointsExtractStatus.ERROR;

  const handleGoBack = () => {
    pointsExtractActions.clearTransactionsFilters();
    pointsExtractActions.reset();
    navigation.goBack();
  };

  const handleRefresh = async () => {
    setIsRefreshing(true);
    await getPointsExtract({ type: 'Resgate' });
    setIsRefreshing(false);
  };

  const hasFocused = useRef(false);
  useFocusEffect(
    React.useCallback(() => {
      if (!hasFocused.current) {
        eventScreenViewV3(
          'meus_pedidos',
          'hub_recompensas_spmais',
          'monetizacao',
          {
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'meus_pedidos',
          },
        );
        pointsExtractActions.clearTransactionsFilters();
        pointsExtractActions.reset();
        getPointsExtract({ type: 'Resgate' });
        hasFocused.current = true;
      }
      return () => {
        hasFocused.current = false;
      };
    }, [pointsExtractActions]),
  );

  return (
    <MyOrdersRewardProgramView
      myOrders={myOrders}
      emptyImage={emptyImage}
      isLoading={isLoading}
      isError={isError}
      filterGroups={getFilterGroups}
      modalizeRefFilters={modalizeRefFilters}
      formatDate={getFormatDate}
      handleGoBack={handleGoBack}
      handleOpenFilters={handleOpenFilters}
      handleDetailsOrders={handleDetailsOrders}
      isRefreshing={isRefreshing}
      handleRefresh={handleRefresh}
      skeletonCount={SKELETON_COUNT}
      screenWidth={width}
      handleApplyFilters={handleApplyFilters}
      initialFilters={getInitialFilters}
      activeFiltersCount={getActiveFiltersCount()}
    />
  );
};

export default MyOrdersRewardProgram;

