import React, { useEffect, useState } from 'react';
import { ScrollView, FlatList, ActivityIndicator } from 'react-native';
import type { Meta, StoryObj } from '@storybook/react';
import {
  Box,
  CardVehicleTags,
  Header,
  Icon,
  Skeleton,
  Text,
} from '@semparar/design-system-app';
import type { PropsIconsNameCore } from '@semparar/design-system-app';
import { NavigationDecorator } from '../../.storybook/decorators/NavigationDecorator';
import { useRootStore } from '~/store';
import {
  PointsExtractStatus,
} from '../services/models/extract.model';
import type { PointsTransaction } from '../services/models/extract.model';

const STATUS_COLORS: Record<string, string> = {
  Pendente: 'highlight',
  Confirmado: 'highlight',
  Enviado: 'success',
  Finalizado: 'success',
  Estornado: 'error',
  Cancelado: 'alert',
};

const MOCK_ORDERS: PointsTransaction[] = [
  {
    id: 'ord-1',
    date: '2026-02-20T14:30:00Z',
    description: 'Voucher para abastecimento',
    type: 'RESCUE',
    amount: -2500,
    currencyValue: 25.0,
    icon: 'icon-gas-station',
    details: {
      provider: 'Shell',
      extraInfo: 'Voucher de desconto',
      fields: [
        { label: 'Desconto total', value: 'R$ 25,00' },
        { label: 'Criado em', value: '20/02/2026' },
        { label: 'Válido até', value: '20/05/2026' },
      ],
    },
    status: 'Finalizado',
    origination: 'VOUCHER',
  },
  {
    id: 'ord-2',
    date: '2026-02-18T10:15:00Z',
    description: 'Voucher para estacionamento',
    type: 'RESCUE',
    amount: -7500,
    currencyValue: 75.0,
    icon: 'icon-parking',
    details: {
      provider: 'Sem Parar',
      extraInfo: 'Voucher de desconto',
      fields: [
        { label: 'Desconto total', value: 'R$ 75,00' },
        { label: 'Criado em', value: '18/02/2026' },
        { label: 'Válido até', value: '18/05/2026' },
      ],
    },
    status: 'Enviado',
    origination: 'VOUCHER',
  },
  {
    id: 'ord-3',
    date: '2026-02-15T16:45:00Z',
    description: 'Cashback na fatura',
    type: 'RESCUE',
    amount: -5000,
    currencyValue: 50.0,
    icon: 'icon-invoice',
    details: {
      provider: 'Sem Parar',
      extraInfo: 'Cashback aplicado na fatura',
      fields: [
        { label: 'Valor do cashback', value: 'R$ 50,00' },
        { label: 'Aplicado em', value: '15/02/2026' },
      ],
    },
    status: 'Pendente',
    origination: 'CASHBACK',
  },
  {
    id: 'ord-4',
    date: '2026-02-12T09:00:00Z',
    description: 'Desconto em multas e débitos',
    type: 'RESCUE',
    amount: -3000,
    currencyValue: 30.0,
    icon: 'icon-document',
    details: {
      provider: 'Sem Parar',
      extraInfo: '',
      fields: [
        { label: 'Desconto total', value: 'R$ 30,00' },
        { label: 'Criado em', value: '12/02/2026' },
      ],
    },
    status: 'Estornado',
    origination: 'VOUCHER',
  },
  {
    id: 'ord-5',
    date: '2026-02-10T11:30:00Z',
    description: 'Voucher para abastecimento',
    type: 'RESCUE',
    amount: -1500,
    currencyValue: 15.0,
    icon: 'icon-gas-station',
    details: {
      provider: 'Shell',
      extraInfo: '',
      fields: [
        { label: 'Desconto total', value: 'R$ 15,00' },
        { label: 'Criado em', value: '10/02/2026' },
        { label: 'Válido até', value: '10/05/2026' },
      ],
    },
    status: 'Cancelado',
    origination: 'VOUCHER',
  },
  {
    id: 'ord-6',
    date: '2026-02-08T08:00:00Z',
    description: 'Voucher para estacionamento',
    type: 'RESCUE',
    amount: -10000,
    currencyValue: 100.0,
    icon: 'icon-parking',
    details: {
      provider: 'Sem Parar',
      extraInfo: '',
      fields: [
        { label: 'Desconto total', value: 'R$ 100,00' },
        { label: 'Utilizado', value: 'R$ 25,00' },
        { label: 'Restante', value: 'R$ 75,00' },
        { label: 'Criado em', value: '08/02/2026' },
        { label: 'Válido até', value: '08/05/2026' },
      ],
    },
    status: 'Confirmado',
    origination: 'VOUCHER',
  },
];

function formatDate(iso?: string): string {
  if (!iso) return '';
  const d = new Date(iso);
  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = d.getFullYear();
  return `${day}/${month}/${year}`;
}

function seedStoreLoaded() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractData({
      transactions: MOCK_ORDERS,
      pagination: { page: 1, pageSize: 20, total: MOCK_ORDERS.length, totalPages: 1 },
    });
  }
}

function seedStoreLoading() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.LOADING);
  }
}

function seedStoreError() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.ERROR);
  }
}

function seedStoreEmpty() {
  const state = useRootStore.getState() as Record<string, any>;
  if (state.pointsExtractActions) {
    state.pointsExtractActions.setExtractData({
      transactions: [],
      pagination: { page: 1, pageSize: 20, total: 0, totalPages: 0 },
    });
  }
}

function ErrorState() {
  return (
    <Box flex={1} justify="center" align="center" pd="innerLarge">
      <Icon name="icon-circle-alert" color="DENY_COLOR_01" size="lg" />
      <Text type="paragraphXXXL" align="center" mt="smaller" mb="xxxs">
        Algo deu errado!
      </Text>
      <Text
        type="paragraphMD"
        align="center"
        color="INTENSE_COLOR_05"
        mb="smaller"
      >
        Por favor, tente mais tarde
      </Text>
    </Box>
  );
}

function EmptyState({ hasActiveFilters }: { hasActiveFilters: boolean }) {
  return (
    <Box align="center" pd="innerLarger" justify="center" mt="larger">
      <Box
        width={80}
        height={80}
        align="center"
        justify="center"
        bgColor="BRAND_COMPLEMENT_02"
        style={{ borderRadius: 40 }}
      >
        <Icon name="icon-shopping-cart" size="lg" color="INTENSE_COLOR_03" />
      </Box>
      {hasActiveFilters ? (
        <Text type="paragraphXXXL" mt="nano" align="center">
          Não há resultados para sua busca
        </Text>
      ) : (
        <>
          <Text type="paragraphXXXL" mt="nano">
            Nenhum pedido feito
          </Text>
          <Text type="paragraphLG" align="center" mt="nano">
            Quando você usar seus pontos em pedidos, eles aparecerão aqui.
          </Text>
        </>
      )}
    </Box>
  );
}

function LoadingState() {
  const SKELETON_COUNT = 3;
  const SCREEN_WIDTH = 390;

  return (
    <Box width={SCREEN_WIDTH} mt="nano">
      {Array.from({ length: SKELETON_COUNT }).map((_, i) => (
        <Skeleton
          key={i}
          width={SCREEN_WIDTH - 64}
          height={150}
          type="light"
          mt="nano"
          mb="nano"
          mr="medium"
          ml="medium"
          borderRadiusTopLeft="half"
        />
      ))}
    </Box>
  );
}

function OrdersList({ orders }: { orders: PointsTransaction[] }) {
  return (
    <>
      {orders.map(item => (
        <Box key={item.id} ml="middle" mr="middle" mt="smaller">
          <CardVehicleTags
            vehicleName={item.description}
            icon={item.icon as PropsIconsNameCore}
            title="Valor em pontos"
            titleDescription={String(Math.abs(item.amount))}
            date="Data do resgate"
            dateNumber={formatDate(item.date)}
            statusTitle="Status do pedido"
            status={item.status}
            ghostButtonText="Exibir detalhes"
            onGhostButtonPress={() => {}}
            type="extended"
            typeTag={(STATUS_COLORS[item.status] ?? 'alert') as any}
            version="2.0"
          />
        </Box>
      ))}
    </>
  );
}

function MyOrdersStoryWrapper({
  isLoading = false,
  hasError = false,
  isEmpty = false,
  hasActiveFilters = false,
}: {
  isLoading?: boolean;
  hasError?: boolean;
  isEmpty?: boolean;
  hasActiveFilters?: boolean;
}) {
  useEffect(() => {
    if (hasError) {
      seedStoreError();
      return;
    }
    if (isLoading) {
      seedStoreLoading();
      return;
    }
    if (isEmpty) {
      seedStoreEmpty();
      return;
    }
    seedStoreLoaded();
  }, [isLoading, hasError, isEmpty]);

  const showFilter = !isLoading && !hasError && !isEmpty;

  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Meus pedidos"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
        iconRight={showFilter ? 'icon-filter-settings' : undefined}
        onPressRight={() => {}}
      />

      {hasError && <ErrorState />}

      {isLoading && <LoadingState />}

      {!isLoading && !hasError && (
        <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
          {isEmpty ? (
            <EmptyState hasActiveFilters={hasActiveFilters} />
          ) : (
            <OrdersList orders={MOCK_ORDERS} />
          )}
        </ScrollView>
      )}
    </Box>
  );
}

const meta: Meta<typeof MyOrdersStoryWrapper> = {
  title: 'Screens/MyOrders',
  component: MyOrdersStoryWrapper,
  decorators: [NavigationDecorator],
  argTypes: {
    isLoading: {
      control: { type: 'boolean' },
      description: 'Loading skeleton state',
    },
    hasError: {
      control: { type: 'boolean' },
      description: 'API error state',
    },
    isEmpty: {
      control: { type: 'boolean' },
      description: 'Empty orders list',
    },
    hasActiveFilters: {
      control: { type: 'boolean' },
      description: 'Show "no results" empty state (when filters are active)',
    },
  },
};

export default meta;
type Story = StoryObj<typeof MyOrdersStoryWrapper>;

export const Loaded: Story = {
  name: 'Loaded (6 orders)',
  args: { isLoading: false, hasError: false, isEmpty: false },
};

export const Empty: Story = {
  name: 'Empty State',
  args: { isEmpty: true, hasActiveFilters: false },
};

export const EmptyWithFilters: Story = {
  name: 'Empty (Filtered)',
  args: { isEmpty: true, hasActiveFilters: true },
};

export const Loading: Story = {
  name: 'Loading State',
  args: { isLoading: true },
};

export const Error: Story = {
  name: 'Error State',
  args: { hasError: true },
};

