  return (
    <Box
      ml="medium"
      mr="medium"
      mt="nano"
      mb="nano"
      height={150}
      bgColor="BRAND_COMPLEMENT_02"
      style={{ borderRadius: 8, overflow: 'hidden' }}
    >
      <Box pd="innerSmall">
        <Box
          width={100}
          height={20}
          bgColor="INTENSE_COLOR_02"
          style={{ borderRadius: 4 }}
          mb="xxxs"
        />
        <Box
          width={200}
          height={18}
          bgColor="INTENSE_COLOR_02"
          style={{ borderRadius: 4 }}
          mb="xxxs"
        />
        <Box
          width={160}
          height={14}
          bgColor="INTENSE_COLOR_02"
          style={{ borderRadius: 4 }}
          mb="xxxs"
        />
        <Box
          width={140}
          height={14}
          bgColor="INTENSE_COLOR_02"
